  1	import { type FC, type MouseEvent, type ReactNode, useEffect, useRef, useState } from 'react';
  2	import { FormGroupWithHelpText } from 'src/components/common/FormGroupWithHelpText/FormGroupWithHelpText';
  3	import { AlertMessageForModals } from 'src/modules/Providers/modals/components/AlertMessageForModals';
  4	import { ItemIsOwnedAlert } from 'src/modules/Providers/modals/components/ItemIsOwnedAlert';
  5	import { defaultOnConfirm } from 'src/modules/Providers/modals/EditModal/utils/defaultOnConfirm';
  6	import { getValueByJsonPath } from 'src/modules/Providers/utils/helpers/getValueByJsonPath';
  7	import { useForkliftTranslation } from 'src/utils/i18n';
  8	
  9	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
 10	import { debounce, Form, TextInput } from '@patternfly/react-core';
 11	import { type ValidationMsg, ValidationState } from '@utils/validation/Validation';
 12	
 13	import type { EditFieldProps } from './EditFieldTypes';
 14	
 15	/**
 16	 * `EditField` is a React Functional Component that allows editing a Kubernetes resource property.
 17	 */
 18	export const EditField: FC<EditFieldProps> = ({
 19	  bodyContent,
 20	  defaultValue = '',
 21	  headerContent,
 22	  helperText,
 23	  InputComponent,
 24	  jsonPath,
 25	  label,
 26	  model,
 27	  onConfirmHook = defaultOnConfirm,
 28	  onSave,
 29	  resource,
 30	  validationHook,
 31	}) => {
 32	  const { t } = useForkliftTranslation();
 33	  const [alertMessage, setAlertMessage] = useState<ReactNode>(null);
 34	  const [value, setValue] = useState(
 35	    (getValueByJsonPath(resource, jsonPath) as string) ?? defaultValue,
 36	  );
 37	  const latestValueRef = useRef(value);
 38	  const [validation, setValidation] = useState<ValidationMsg>({
 39	    msg: null,
 40	    type: ValidationState.Default,
 41	  });
 42	
 43	  const { namespace } = resource?.metadata ?? {};
 44	  const owner = resource?.metadata?.ownerReferences?.[0];
 45	
 46	  useEffect(() => {
 47	    latestValueRef.current = value;
 48	  }, [value]);
 49	
 50	  /*
 51	   * Init validation
 52	   */
 53	  useEffect(() => {
 54	    if (validationHook) {
 55	      const validationResult = validationHook(value);
 56	      setValidation(validationResult);
 57	    }
 58	  }, [value, validationHook]);
 59	
 60	  /*
 61	   * Updates the value when changed from outside
 62	   * TODO: Causes issue where state update 'fights' with user input
 63	   */
 64	  // useEffect(() => {
 65	  //   setValue(getValueByJsonPath(resource, jsonPath) as string);
 66	  // }, [resource, jsonPath]);
 67	
 68	  /**
 69	   * Handles save action.
 70	   */
 71	  const handleSave = async () => {
 72	    try {
 73	      await onConfirmHook({ jsonPath, model, newValue: latestValueRef.current, resource });
 74	      onSave?.();
 75	    } catch (err) {
 76	      const message = (err as Error)?.message ?? err;
 77	      setAlertMessage(message);
 78	    }
 79	  };
 80	
 81	  const debouncedSaveRef = useRef(debounce(handleSave, 500));
 82	
 83	  /**
 84	   * Handles value change.
 85	   */
 86	  const handleValueChange = (newValue: string) => {
 87	    setValue(() => newValue);
 88	
 89	    if (validationHook) {
 90	      const validationResult = validationHook(newValue);
 91	      setValidation(validationResult);
 92	    }
 93	
 94	    debouncedSaveRef.current();
 95	  };
 96	
 97	  const onClick: (event: MouseEvent<HTMLButtonElement>) => void = (event) => {
 98	    event.preventDefault();
 99	  };
100	
101	  /**
102	   * InputComponentWithDefault is a higher-order component that renders either the passed-in InputComponent, or a default TextInput,
103	   */
104	  const InputComponentWithDefault = InputComponent ? (
105	    <InputComponent
106	      value={value}
107	      onChange={(val) => {
108	        handleValueChange(val as string);
109	      }}
110	    />
111	  ) : (
112	    <TextInput
113	      spellCheck="false"
114	      id="modal-with-form-form-field"
115	      name="modal-with-form-form-field"
116	      value={value}
117	      onChange={(_e, val) => {
118	        handleValueChange(val);
119	      }}
120	      validated={validation.type}
121	    />
122	  );
123	
124	  return (
125	    <>
126	      <Form id="modal-with-form-form">
127	        <FormGroupWithHelpText
128	          label={label}
129	          labelIcon={
130	            headerContent && bodyContent ? (
131	              <HelpIconPopover header={headerContent} onClick={onClick}>
132	                {bodyContent}
133	              </HelpIconPopover>
134	            ) : undefined
135	          }
136	          fieldId="modal-with-form-form-field"
137	          helperText={validation.msg ?? helperText}
138	          helperTextInvalid={validation.msg ?? helperText}
139	          validated={validation.type}
140	        >
141	          {InputComponentWithDefault}
142	        </FormGroupWithHelpText>
143	        {typeof owner === 'object' && (
144	          <ItemIsOwnedAlert owner={owner} namespace={namespace} className="" />
145	        )}
146	        {alertMessage && (
147	          <AlertMessageForModals title={t('Error')} message={alertMessage} className="" />
148	        )}
149	      </Form>
150	    </>
151	  );
152	};

